#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 100005
#define MAXK 100005
#define MAXL 100005
#define INF 0x3f3f3f3f

int n, k, l;
int u[MAXN], v[MAXL];
int dist[MAXN][MAXN];
int graph[MAXN][MAXN];

void bfs(int start, int *dist) {
    int queue[MAXN];
    int front = 0, rear = 0;
    queue[rear++] = start;
    dist[start] = 0;
    while (front < rear) {
        int node = queue[front++];
        for (int i = 1; i <= n; i++) {
            if (graph[node][i] && dist[i] == INF) {
                queue[rear++] = i;
                dist[i] = dist[node] + 1;
            }
        }
    }
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d %d", &n, &k, &l);
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                graph[i][j] = 0;
                dist[i][j] = INF;
            }
        }
        for (int i = 1; i < n; i++) {
            int p, q;
            scanf("%d %d", &p, &q);
            graph[p][q] = graph[q][p] = 1;
        }
        for (int i = 1; i <= k; i++) {
            scanf("%d", &u[i]);
        }
        for (int i = 1; i <= l; i++) {
            scanf("%d", &v[i]);
        }
        int count = 0;
        for (int i = 1; i <= k; i++) {
            for (int j = 1; j <= l; j++) {
                bfs(u[i], dist[u[i]]);
                bfs(v[j], dist[v[j]]);
                if (dist[u[i]][v[j]] == dist[v[j]][u[i]]) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

