import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAXN = 100005;
    static final int MAXK = 100005;
    static final int MAXL = 100005;
    static final int INF = 0x3f3f3f3f;

    static int n, k, l;
    static int[] u = new int[MAXK];
    static int[] v = new int[MAXL];
    static int[][] dist = new int[MAXN][MAXN];
    static int[][] graph = new int[MAXN][MAXN];

    public static void bfs(int start, int[] dist, int[][] graph) {
        Queue<Integer> q = new LinkedList<>();
        q.offer(start);
        dist[start] = 0;
        while (!q.isEmpty()) {
            int node = q.poll();
            for (int i = 1; i <= n; i++) {
                if (graph[node][i] == 1 && dist[i] == INF) {
                    q.offer(i);
                    dist[i] = dist[node] + 1;
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            n = sc.nextInt();
            k = sc.nextInt();
            l = sc.nextInt();
            for (int i = 1; i <= n; i++) {
                for (int j = 1; j <= n; j++) {
                    graph[i][j] = 0;
                    dist[i][j] = INF;
                }
            }
            for (int i = 1; i < n; i++) {
                int p = sc.nextInt();
                int q = sc.nextInt();
                graph[p][q] = graph[q][p] = 1;
            }
            for (int i = 1; i <= k; i++) {
                u[i] = sc.nextInt();
            }
            for (int i = 1; i <= l; i++) {
                v[i] = sc.nextInt();
            }
            int count = 0;
            for (int i = 1; i <= k; i++) {
                for (int j = 1; j <= l; j++) {
                    bfs(u[i], dist[u[i]], graph);
                    bfs(v[j], dist[v[j]], graph);
                    if (dist[u[i]][v[j]] == dist[v[j]][u[i]]) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

